// Example rendering logic
{#each $currentSource[0].sections as section}
  <section id={section.id}>
    <h2>{section.title}</h2>
    <p>{@html section.intro}</p>
    {#each section.subtopics as subtopic}
      {#each subtopic.blocks as block}
        {#if block.type === 'text'}
          <p>{@html formatText(block.value)}</p>
        {:else if block.type === 'code'}
          <CodeSnippet code={block.value} />
        {:else if block.type === 'note'}
          <InlineNotification kind={block.kind} />
        {/if}
      {/each}
    {/each}
  </section>
{/each}

